        {/* 2. EDIT (INPAINT) CONTROLS */}
        {isEditMode && (
           <div className="flex flex-col gap-4 bg-zinc-900 border border-zinc-800 p-4 rounded-xl">
               <h3 className="text-xs font-bold text-zinc-400 uppercase">Pengaturan Kuas</h3>
               <div className="flex flex-col gap-2">
                  <div className="flex justify-between items-center">
                    <label className="text-xs text-zinc-500">Ukuran Kuas</label>
                    <span className="text-xs text-white font-mono">{brushSize}px</span>
                  </div>
                  <input 
                    type="range" min="5" max="100" step="1" 
                    value={brushSize} 
                    onChange={(e) => setBrushSize(Number(e.target.value))} 
                    className="w-full accent-teal-500 h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer"
                  />
               </div>
               <button onClick={clearCanvas} className="text-xs text-red-400 hover:text-red-300 border border-red-900/50 bg-red-900/10 px-3 py-2 rounded transition-colors w-full">
                  Hapus Seleksi
               </button>

               <div className="border-t border-zinc-800 pt-2"></div>

               {/* Controls for Edit Mode use custom handler */}
               <Controls 
                  onGenerate={(prompt, aspectRatio) => handleInpaintGenerate(prompt)}
                  isLoading={loading}
                  disabled={loading || !originalImage}
                  selectedFeature={selectedFeature}
               />
           </div>
        )}

        {/* 3. STANDARD CONTROLS (Fallback) */}
        {!isExpandMode && !isEditMode && (
            <Controls 
                onGenerate={(prompt, aspectRatio) => {
                   if (isMascotMode) {
                       handleMascotGenerate(prompt, aspectRatio);
                   } else if (isMultiMode) {
                       handleCompositeGenerate(prompt, aspectRatio);
                   } else if (isBannerMode) {
                       handleBannerGenerate(prompt, aspectRatio);
                   } else {
                       parentOnGenerate(prompt, aspectRatio);
                   }
                }}
                isLoading={loading}
                // Mascot mode allows execution even if !originalImage
                disabled={loading || (isMultiMode && uploadedImages.length < (isProductMode && !useModel ? 1 : 2)) || (!isMultiMode && !originalImage && !isMascotMode)}
                selectedFeature={selectedFeature}
                // HIDE INPUTS FOR FACE SWAP
                hidePromptInput={isFaceSwap}
            />
        )}
      </div>


      {/* --- RIGHT COLUMN: RESULT DISPLAY (70%) --- */}
      <div className="w-full lg:w-[70%] bg-zinc-900/30 rounded-2xl border border-zinc-800/50 p-4 relative min-h-[500px]">

        {/* Loading Overlay State */}
        {loading && (
          <div className="absolute top-4 right-4 z-10 bg-teal-600 text-white text-xs font-bold px-3 py-1.5 rounded-full shadow-lg animate-pulse flex items-center gap-2">
             <div className="w-2 h-2 bg-white rounded-full animate-bounce"></div>
             {isMultiMode && !isFaceSwap ? `Membuat Variasi ${generationCount} dari 4` : 'Memproses Gambar...'}
          </div>
        )}

        {/* CONTENT LOGIC */}
        {(isMultiMode || isMascotMode) && !isFaceSwap ? (
          <div className="flex flex-col gap-4">
            <h3 className="text-xs font-bold text-zinc-500 uppercase tracking-wider sticky top-0 bg-zinc-950/80 backdrop-blur-md py-2 z-10 rounded-lg px-2">
              {isMascotMode ? "Hasil Maskot" : (isProductMode ? "Hasil Foto Produk (4 Variasi)" : "Variasi Hasil (Grid 2x2)")}
            </h3>

            <div className={`grid gap-4 ${isMascotMode ? 'grid-cols-1 md:grid-cols-1' : 'grid-cols-1 md:grid-cols-2'}`}>
              {displayResults.map((result, index) => (
                  <div 
                    key={index} 
                    className={`relative w-full aspect-square rounded-xl overflow-hidden border-2 transition-all 
                      ${result ? 'border-teal-500/50 bg-black' : 'border-zinc-800 bg-zinc-900/50 border-dashed'}
                    `}
                  >
                      <div className="group w-full h-full relative">
                        <img src={`data:image/png;base64,${result.result}`} className="w-full h-full object-contain" />
                        <div className="absolute top-2 left-2 bg-black/60 text-white text-[10px] px-2 py-0.5 rounded backdrop-blur-sm">
                          Hasil {index + 1}
                        </div>
                        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                           <a 
                            href={`data:image/png;base64,${result.result}`} 
                            download={`studio-ai-v${index+1}.png`}
                            className="p-2 bg-white text-black rounded-full hover:scale-110 transition-transform"
                            title="Unduh"
                           >
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M12 12v8.25m0-8.25l-3 3m3-3l3 3m-6-6h6m-6 0v6" />
                              </svg>
                           </a>
                           <button 
                            onClick={() => onSelectResult(result)}
                            className="p-2 bg-teal-600 text-white rounded-full hover:scale-110 transition-transform"
                            title="Lihat Layar Penuh"
                           >
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 3.75v4.5m0-4.5h4.5m-4.5 0L9 9M20.25 20.25v-4.5m0 4.5h-4.5m4.5 0L15 15M3.75 20.25h4.5m-4.5 0v-4.5m0 4.5L9 15M20.25 3.75h-4.5m4.5 0v4.5m0 4.5L15 9" />
                              </svg>
                           </button>
                        </div>
                      </div>
                  </div>
              ))}
              {displayResults.length === 0 && !loading && (
                  <div className="w-full aspect-square flex flex-col items-center justify-center text-zinc-700 bg-zinc-900/20 rounded-xl border-2 border-dashed border-zinc-800">
                      <span className="text-sm">Hasil akan muncul di sini</span>
                  </div>
              )}
            </div>
          </div>
        ) : (
          // SINGLE MODE (Or Expand/Edit Result / FaceSwap Single Result): LARGE PREVIEW
          <div className="flex flex-col">
             {/* 
                 Logic for showing result in Edit Mode:
                 1. We use ComparisonView.
                 2. originalImage is still the base original.
                 3. resultImage is from localCompositeResults if available.
             */}
             <ComparisonView 
                originalImage={isExpandMode && localCompositeResults.length > 0 
                    ? localCompositeResults[0].original 
                    : (originalImage || (uploadedImages[1] ? `data:${uploadedImages[1].mimeType};base64,${uploadedImages[1].base64}` : ''))
                }
                resultImage={
                    ((isExpandMode || isEditMode || isFaceSwap) && localCompositeResults.length > 0)
                    ? localCompositeResults[0].result
                    : (activeResultId && displayResults.find(r => r.id === activeResultId)?.result || null)
                }
                isLoading={loading}
              />

              {!originalImage && !loading && !uploadedImages[1] && (
                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-50">
                    <div className="text-center">
                      <div className="w-20 h-20 bg-zinc-800 rounded-full mx-auto mb-4 flex items-center justify-center">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1} stroke="currentColor" className="w-10 h-10 text-zinc-600">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 15.75l5.159-5.159a2.25 2.25 0 013.182 0l5.159 5.159m-1.5-1.5l1.409-1.409a2.25 2.25 0 013.182 0l2.909 2.909m-18 3.75h16.5a1.5 1.5 0 001.5-1.5V6a1.5 1.5 0 00-1.5-1.5H3.75A1.5 1.5 0 002.25 6v12a1.5 1.5 0 001.5 1.5zm10.5-11.25h.008v.008h-.008V8.25zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0z" />
                        </svg>
                      </div>
                      <p className="text-zinc-600 font-medium">Area Pratinjau</p>
                    </div>
                 </div>
              )}
          </div>
        )}

      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { FeatureItem, ProcessedImage, AspectRatio } from '../types';
import { ImageUploader } from './ImageUploader';
import { ComparisonView } from './ComparisonView';
import { Controls } from './Controls';
import { generateCompositeImage, editImageWithGemini } from '../services/geminiService';

interface WorkspaceProps {
  selectedFeature: FeatureItem | null;
  originalImage: string | null;
  results: ProcessedImage[];
  isProcessing: boolean;
  onImageSelected: (base64: string, mimeType: string) => void;
  onGenerate: (prompt: string, aspectRatio?: string) => void;
  onSelectResult: (result: ProcessedImage) => void;
  onReset: () => void;
  activeResultId: string | null;
  userApiKey?: string; // NEW PROP
}

export const Workspace: React.FC<WorkspaceProps> = ({
  selectedFeature,
  originalImage,
  results,
  isProcessing,
  onImageSelected,
  onGenerate: parentOnGenerate,
  onSelectResult,
  onReset,
  activeResultId,
  userApiKey
}) => {
  const [uploadedImages, setUploadedImages] = useState<{base64: string, mimeType: string}[]>([]);
  const [internalProcessing, setInternalProcessing] = useState(false);
  const [generationCount, setGenerationCount] = useState(0);

  // Feature specific states
  const [useModel, setUseModel] = useState(false); // For Product Photo

  // Mascot Feature States
  const [mascotType, setMascotType] = useState('Kartun');
  const [brandColor, setBrandColor] = useState('');

  // Banner Feature State
  const [bannerTexts, setBannerTexts] = useState({ main: '', support: '', footer: '' });
  const [bannerStyle, setBannerStyle] = useState('simple'); // simple, background, pro
  const [showCTA, setShowCTA] = useState(false);
  const [ctaText, setCtaText] = useState('');

  // Expand Feature State
  const [expandSettings, setExpandSettings] = useState({ top: 0, right: 0, bottom: 0, left: 0 });
  const [imgDimensions, setImgDimensions] = useState<{w: number, h: number} | null>(null);

  // Edit (Inpainting) Feature State
  const [brushSize, setBrushSize] = useState(30);
  const [isDrawing, setIsDrawing] = useState(false);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  useEffect(() => {
    if (selectedFeature?.allowMultiUpload) {
      setUploadedImages([]);
    }
    // Reset states
    setUseModel(false);
    setMascotType('Kartun');
    setBrandColor('');
    setBannerTexts({ main: '', support: '', footer: '' });
    setBannerStyle('simple');
    setShowCTA(false);
    setCtaText('');
    setExpandSettings({ top: 0, right: 0, bottom: 0, left: 0 });
    clearCanvas();
  }, [selectedFeature]);

  // Load image dimensions when originalImage changes
  useEffect(() => {
    if (originalImage) {
      const img = new Image();
      img.src = originalImage;
      img.onload = () => {
        setImgDimensions({ w: img.width, h: img.height });
        // Resize canvas to match image intrinsic size if in edit mode
        if (selectedFeature?.id === 'edit' && canvasRef.current) {
          canvasRef.current.width = img.width;
          canvasRef.current.height = img.height;
        }
      };
    } else {
      setImgDimensions(null);
    }
  }, [originalImage, selectedFeature]);

  const clearCanvas = () => {
    if (canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      if (ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  const handleMultiImageUpload = (base64: string, mimeType: string) => {
    if (uploadedImages.length >= 5) return;
    setUploadedImages(prev => [...prev, { base64, mimeType }]);
  };

  const removeImage = (index: number) => {
    setUploadedImages(prev => prev.filter((_, i) => i !== index));
  };

  // --- DRAWING LOGIC (EDIT MODE) ---
  const getCoordinates = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;

    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - rect.left) * scaleX,
      y: (clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const { x, y } = getCoordinates(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.strokeStyle = 'rgba(20, 184, 166, 0.5)'; // Teal-500 50%
      ctx.lineWidth = brushSize;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || !canvasRef.current) return;
    e.preventDefault(); // Prevent scrolling on touch
    const { x, y } = getCoordinates(e);
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) {
      ctx.lineTo(x, y);
      ctx.stroke();
    }
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx) ctx.closePath();
  };


  // --- LOGIC FOR COMPOSITE (JOIN) & PRODUCT + MODEL ---
  const [localCompositeResults, setLocalCompositeResults] = useState<ProcessedImage[]>([]);

  const handleCompositeGenerate = async (prompt: string, aspectRatio?: AspectRatio) => {
    const isFaceSwap = selectedFeature?.id === 'faceswap';
    const isProduct = selectedFeature?.id === 'product';
    const isCarousel = selectedFeature?.id === 'carousel';

    if (isFaceSwap && uploadedImages.length !== 2) {
      alert("Untuk Face Swap, Anda wajib mengunggah 2 foto: 1. Wajah Sumber, 2. Foto Target.");
      return;
    }

    if (isProduct) {
        if (useModel && uploadedImages.length !== 2) {
            alert("Mode 'Dengan Model' memerlukan 2 foto: 1. Produk, 2. Model.");
            return;
        }
        if (!useModel && uploadedImages.length < 1) {
             alert("Mohon unggah foto produk.");
             return;
        }
    }

    // Carousel allows 0 uploaded images (text to image) or multiple
    if (!isFaceSwap && !isProduct && !isCarousel && uploadedImages.length < 2) {
      alert("Mohon unggah minimal 2 foto untuk digabungkan.");
      return;
    }

    setInternalProcessing(true);
    setLocalCompositeResults([]); 

    // Construct instructions
    let instruction = selectedFeature?.systemPrompt;
    let finalPrompt = prompt;

    // CUSTOM LOGIC FOR FACE SWAP
    if (isFaceSwap) {
       // Override system prompt for better results
       instruction = `
         ROLE: Elite VFX Artist specializing in High-Fidelity Face Replacement.

         [INPUT IDENTIFICATION]
         - **IMAGE 1 (First Input)**: SOURCE FACE IDENTITY (The face to copy).
         - **IMAGE 2 (Second Input)**: TARGET BODY/SCENE (The image to edit).

         [TASK]
         Take the face from IMAGE 1 and put it onto the person in IMAGE 2.

         [STRICT RULES]
         1. The final output must be **IMAGE 2** with a new face. 
         2. DO NOT use Image 1 as the background. Image 1 is ONLY a reference for the face features.
         3. KEEP Image 2's hair, ears, head shape, neck, body, clothes, and background EXACTLY the same.
         4. BLEND the Source Face (from Image 1) seamlessly into Image 2, matching the skin tone and lighting of Image 2.
       `.trim();

       // Override prompt to ensure model focuses on the task
       finalPrompt = `
         FACE SWAP OPERATION:
         Base Image: The SECOND image provided.
         Face Source: The FIRST image provided.

         INSTRUCTION: Replace the face of the person in the Base Image (2nd) with the face from the Source Image (1st).
         PRESERVE the Base Image's background, hair, body, and lighting 100%. 
         Output must look like the Base Image, but with the Source Image's facial identity.
       `.trim();
    } else if (isProduct && useModel) {
       instruction = selectedFeature?.systemPrompt + " [IMPORTANT: Image 1 is the PRODUCT to advertise. Image 2 is the MODEL REFERENCE. Create a professional scene where this specific model interacts with the product naturally.]";
    }

    // Determine loop count: FaceSwap = 1 result, others (like Product/Carousel) = 4 variations/slides
    const loopCount = isFaceSwap ? 1 : 4;

    for (let i = 0; i < loopCount; i++) {
      setGenerationCount(i + 1);
      try {

        let currentPrompt = finalPrompt;

        // --- PROMPT INJECTION LOGIC ---
        if (isCarousel) {
           // Carousel needs sequential narrative
           const slideNum = i + 1;
           let slideRole = "";
           if (slideNum === 1) slideRole = "SLIDE 1 (HOOK): Main Headline and engaging visual intro.";
           if (slideNum === 2) slideRole = "SLIDE 2 (CONTENT): Explanation part 1 or main benefit display.";
           if (slideNum === 3) slideRole = "SLIDE 3 (CONTENT): Explanation part 2 or detailed feature.";
           if (slideNum === 4) slideRole = "SLIDE 4 (CTA/CONCLUSION): Summary and Call to Action.";

           currentPrompt = `
             ${finalPrompt}

             [CAROUSEL GENERATION SEQUENCE - SLIDE ${slideNum} OF 4]
             CONTEXT: This is image #${slideNum} of a 4-part continuous Instagram Carousel.
             TASK: ${slideRole}
             DESIGN RULES: 
             1. Maintain EXACTLY the same visual style, fonts, and color palette as the other slides in this sequence.
             2. Use the provided image(s) as the visual anchor.
             3. Ensure the text (if any) is large and legible.
           `.trim();
        } else if (!isFaceSwap && loopCount > 1) {
           // Standard Variations (Product, etc)
           currentPrompt = `${finalPrompt} \n\n[VARIATION ${i+1}/${loopCount}]: Make this result unique in terms of angle, lighting, or composition compared to other variations.`;
        }

        // Logic split: If Carousel has no uploaded images, use editImageWithGemini (Text to Image)
        // Otherwise use generateCompositeImage
        let resultBase64 = "";

        if (isCarousel && uploadedImages.length === 0) {
             // Text-to-Image Carousel
             resultBase64 = await editImageWithGemini(
                null,
                "image/png",
                currentPrompt,
                instruction,
                aspectRatio || '1:1',
                userApiKey
             );
        } else {
             // Image-to-Image (Composite)
             resultBase64 = await generateCompositeImage(
              uploadedImages,
              currentPrompt,
              aspectRatio || '1:1',
              instruction,
              userApiKey // PASS API KEY
            );
        }

        const newResult: ProcessedImage = {
          id: Date.now().toString() + i,
          original: uploadedImages.length > 0 ? `data:${uploadedImages[0].mimeType};base64,${uploadedImages[0].base64}` : `data:image/png;base64,${resultBase64}`,
          result: resultBase64,
          prompt: finalPrompt,
          timestamp: Date.now()
        };

        setLocalCompositeResults(prev => [...prev, newResult]);
      } catch (error) {
        console.error("Error generating composite", error);
      }
    }
    setInternalProcessing(false);
    setGenerationCount(0);
  };

  // --- LOGIC FOR INPAINTING (EDIT) ---
  const handleInpaintGenerate = async (prompt: string) => {
    if (!originalImage || !canvasRef.current || !imgDimensions) return;

    setInternalProcessing(true);
    try {
      // 1. Create a temporary canvas to process the mask
      const tempCanvas = document.createElement('canvas');
      tempCanvas.width = imgDimensions.w;
      tempCanvas.height = imgDimensions.h;
      const ctx = tempCanvas.getContext('2d');
      if (!ctx) throw new Error("Context failed");

      // 2. Draw the original image first
      const img = new Image();
      img.src = originalImage;
      await new Promise(r => img.onload = r);
      ctx.drawImage(img, 0, 0);

      // 3. Get image data from original and mask canvas
      const originalData = ctx.getImageData(0, 0, tempCanvas.width, tempCanvas.height);
      const maskCtx = canvasRef.current.getContext('2d');
      if (!maskCtx) throw new Error("Mask context failed");
      const maskData = maskCtx.getImageData(0, 0, tempCanvas.width, tempCanvas.height);

      // 4. Punch holes: If mask pixel alpha > 0, make original pixel transparent
      for (let i = 0; i < maskData.data.length; i += 4) {
        // maskData.data[i+3] is Alpha channel
        if (maskData.data[i + 3] > 0) {
          originalData.data[i + 3] = 0; // Make transparent
        }
      }

      // 5. Put modified data back
      ctx.putImageData(originalData, 0, 0);

      // 6. Get base64 of the "holed" image
      const holedBase64 = tempCanvas.toDataURL('image/png').split(',')[1];

      // 7. Send to Gemini
      // Update prompt as requested: "tambahkan (instruksi) pada area yang diseleksi menggunakan brush..."
      const finalPrompt = `tambahkan ${prompt} pada area yang diseleksi menggunakan brush, gambar tampak menyaru secara natural menyesuaikan style, lighting dan visual pada gambar referensi yang diupload`;

      const resultBase64 = await editImageWithGemini(
        holedBase64,
        'image/png',
        finalPrompt,
        "ROLE: Expert Inpainter. TASK: Fill transparent areas seamlessly.",
        '1:1', // Default
        userApiKey // PASS API KEY
      );

      const newResult: ProcessedImage = {
        id: Date.now().toString(),
        original: originalImage,
        result: resultBase64,
        prompt: prompt,
        timestamp: Date.now()
      };

      setLocalCompositeResults([newResult]); // Reuse local storage for simplicity
      onSelectResult(newResult);

    } catch (e) {
      console.error(e);
      alert("Gagal mengedit gambar.");
    } finally {
      setInternalProcessing(false);
    }
  };

  // --- LOGIC FOR EXPAND (OUTPAINTING) ---
  const setExpandRatio = (ratioW: number, ratioH: number) => {
    if (!imgDimensions) return;

    const currentAspect = imgDimensions.w / imgDimensions.h;
    const targetAspect = ratioW / ratioH;

    let newTop = 0, newBottom = 0, newLeft = 0, newRight = 0;

    if (currentAspect > targetAspect) {
      // Image is wider than target. Need to add vertical space (top/bottom)
      // target = W / H_new  => H_new = W / target
      const newH = imgDimensions.w / targetAspect;
      const totalPadH = newH - imgDimensions.h;
      // Split padding evenly
      const pct = (totalPadH / 2) / imgDimensions.h * 100;
      newTop = pct;
      newBottom = pct;
      newLeft = 0;
      newRight = 0;
    } else {
      // Image is taller than target. Need to add horizontal space (left/right)
      // target = W_new / H => W_new = H * target
      const newW = imgDimensions.h * targetAspect;
      const totalPadW = newW - imgDimensions.w;
      const pct = (totalPadW / 2) / imgDimensions.w * 100;
      newLeft = pct;
      newRight = pct;
      newTop = 0;
      newBottom = 0;
    }

    setExpandSettings({ top: newTop, bottom: newBottom, left: newLeft, right: newRight });
  };

  const handleExpandGenerate = async () => {
    if (!originalImage) return;

    // Check if expansion is actually requested
    if (expandSettings.top === 0 && expandSettings.bottom === 0 && expandSettings.left === 0 && expandSettings.right === 0) {
      alert("Harap atur slider atau pilih rasio untuk memperluas area.");
      return;
    }

    setInternalProcessing(true);

    try {
      // 1. Create Canvas and pad image
      const img = new Image();
      img.src = originalImage;
      await new Promise(r => img.onload = r);

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) throw new Error("Canvas context failed");

      const w = img.width;
      const h = img.height;

      // Calculate percentages to pixels
      const pTop = (expandSettings.top / 100) * h;
      const pBottom = (expandSettings.bottom / 100) * h;
      const pLeft = (expandSettings.left / 100) * w;
      const pRight = (expandSettings.right / 100) * w;

      const newW = w + pLeft + pRight;
      const newH = h + pTop + pBottom;

      canvas.width = newW;
      canvas.height = newH;

      // Fill background with white/context color for AI to understand it's empty
      ctx.fillStyle = "#ffffff"; 
      ctx.fillRect(0, 0, newW, newH);

      // Draw original image in correct position
      ctx.drawImage(img, pLeft, pTop, w, h);

      // Get new Base64
      const paddedBase64Full = canvas.toDataURL('image/png');
      const paddedBase64Raw = paddedBase64Full.split(',')[1];

      // 2. Send to Gemini
      const autoPrompt = "Outpaint: Fill the surrounding white space seamlessly to expand the scenery. Match the lighting, texture, and perspective of the central original image naturally.";

      const resultBase64 = await editImageWithGemini(
        paddedBase64Raw,
        'image/png',
        autoPrompt,
        selectedFeature?.systemPrompt,
        '1:1', // Default aspect ratio for expand call (it follows image config actually, but param required)
        userApiKey // PASS API KEY
      );

      const newResult: ProcessedImage = {
        id: Date.now().toString(),
        original: paddedBase64Full,
        result: resultBase64,
        prompt: autoPrompt,
        timestamp: Date.now()
      };

      setLocalCompositeResults([newResult]);
      onSelectResult(newResult);

    } catch (e) {
      console.error(e);
      alert("Gagal memperluas gambar.");
    } finally {
      setInternalProcessing(false);
    }
  };

  // --- HANDLER FOR MASCOT GENERATION ---
  const handleMascotGenerate = async (userPrompt: string, aspectRatio?: AspectRatio) => {
      setInternalProcessing(true);
      try {
          // Construct specific prompt
          const specificPrompt = `
            [USER PROMPT]: ${userPrompt}
            [MASCOT TYPE]: ${mascotType}
            [BRAND COLOR]: ${brandColor || "Not Specified"}
            [INSTRUCTION]: Create a mascot of type '${mascotType}'. Use '${brandColor}' as the primary brand color for clothing/accents.
          `.trim();

          const base64Raw = originalImage ? originalImage.split(',')[1] : null;
          // Note: editImageWithGemini has been updated to accept null base64Raw for Text-to-Image
          const resultBase64 = await editImageWithGemini(
            base64Raw,
            'image/png', // Default mime if no image, wrapper handles it
            specificPrompt,
            selectedFeature?.systemPrompt,
            aspectRatio,
            userApiKey // PASS API KEY
          );

          // Use a placeholder or the original image for the "original" field in result
          const originDisplay = originalImage || `data:image/png;base64,${resultBase64}`; 

          const newResult: ProcessedImage = {
            id: Date.now().toString(),
            original: originDisplay,
            result: resultBase64,
            prompt: specificPrompt,
            timestamp: Date.now()
          };

          setLocalCompositeResults([newResult]);
          onSelectResult(newResult);

      } catch (e: any) {
          console.error(e);
          alert("Gagal membuat maskot: " + e.message);
      } finally {
          setInternalProcessing(false);
      }
  };

  // --- HANDLER FOR BANNER GENERATION ---
  const handleBannerGenerate = (userPrompt: string, aspectRatio?: AspectRatio) => {

    let styleInstructions = "";
    if (bannerStyle === 'simple') {
      styleInstructions = "STYLE: Clean, Minimalist. Focus strictly on the image and text placement. No extra decorations. Use a solid or subtle gradient background that contrasts well with the text.";
    } else if (bannerStyle === 'background') {
      styleInstructions = "STYLE: Creative Background. Generate a rich, thematic background that complements the main subject. Apply cinematic color grading and lighting effects. The text should sit naturally within the environment.";
    } else if (bannerStyle === 'pro') {
      styleInstructions = "STYLE: High-End Professional Poster. Complex composition. Add graphic elements (shapes, lines, frames), textures, and overlays. Apply advanced typography effects (3D, shadow, neon, metallic). Use dynamic visual effects (lens flares, particles, depth of field).";
    }

    const ctaInstruction = showCTA 
      ? `[CTA REQUIREMENT]: Design a prominent, high-contrast Call-to-Action button or highlighted text area with the content: "${ctaText}". Ensure it draws attention.` 
      : "[CTA REQUIREMENT]: No specific button needed.";

    const textInfo = `
    [BANNER SPECIFICATIONS]
    ${styleInstructions}

    [TEXT CONTENT]
    1. MAIN HEADLINE (Big/Bold): "${bannerTexts.main}"
    2. SUPPORTING TEXT: "${bannerTexts.support}"
    3. FOOTER/INFO: "${bannerTexts.footer}"

    ${ctaInstruction}

    [DESIGN THEME/PROMPT]
    ${userPrompt}
    `;
    parentOnGenerate(textInfo.trim(), aspectRatio);
  };

  const isMultiMode = selectedFeature?.allowMultiUpload;
  const isExpandMode = selectedFeature?.id === 'expand';
  const isEditMode = selectedFeature?.id === 'edit';
  const isFaceSwap = selectedFeature?.id === 'faceswap';
  const isProductMode = selectedFeature?.id === 'product';
  const isMascotMode = selectedFeature?.id === 'mascot';
  const isBannerMode = selectedFeature?.id === 'banner';
  const isCarouselMode = selectedFeature?.id === 'carousel';

  // Decide which results to show
  // Carousel is treated as a multi-result feature (grid display)
  const displayResults = (isMultiMode || isExpandMode || isEditMode || isMascotMode || isCarouselMode) ? localCompositeResults : results;
  const loading = isProcessing || internalProcessing;

  if (!selectedFeature) {
    return (
      <div className="flex flex-col items-center justify-center h-full min-h-[50vh] animate-fade-in-up">
