                      value={mascotType} 
                      onChange={(e) => setMascotType(e.target.value)}
                      className="w-full bg-zinc-800 text-white text-sm p-2 rounded-lg border border-zinc-700 focus:border-teal-500 outline-none"
                    >
                        <option value="Hewan">Hewan</option>
                        <option value="Manusia">Manusia</option>
                        <option value="Kartun">Kartun</option>
                        <option value="3D">3D</option>
                        <option value="Chibi">Chibi</option>
                    </select>
                 </div>

                 {/* Color Input */}
                 <div className="flex flex-col gap-2">
                    <label className="text-[10px] text-zinc-500">Warna Brand (Dominan)</label>
                    <input 
                      type="text"
                      value={brandColor}
                      onChange={(e) => setBrandColor(e.target.value)}
                      placeholder="Contoh: Biru Tosca dan Putih"
                      className="w-full bg-zinc-800 text-white text-sm p-2 rounded-lg border border-zinc-700 focus:border-teal-500 outline-none placeholder-zinc-600"
                    />
                 </div>
            </div>
        )}

        {/* 0.5 BANNER CONTROLS */}
        {isBannerMode && (
            <div className="flex flex-col gap-4 bg-zinc-900 border border-zinc-800 p-4 rounded-xl">
                 <h3 className="text-xs font-bold text-zinc-400 uppercase">Konten Banner</h3>

                 {/* Style Selector */}
                 <div className="flex flex-col gap-2">
                    <label className="text-[10px] text-zinc-500">Gaya Visual</label>
                    <select 
                      value={bannerStyle} 
                      onChange={(e) => setBannerStyle(e.target.value)}
                      className="w-full bg-zinc-800 text-white text-sm p-2 rounded-lg border border-zinc-700 focus:border-teal-500 outline-none"
                    >
                        <option value="simple">Gambar + Teks Saja</option>
                        <option value="background">Variasi Background & Efek</option>
                        <option value="pro">Poster Profesional (Full Effect)</option>
                    </select>
                 </div>

                 <div className="flex flex-col gap-2">
                    <label className="text-[10px] text-zinc-500">Teks Utama (Headline)</label>
                    <input 
                      type="text"
                      value={bannerTexts.main}
                      onChange={(e) => setBannerTexts(prev => ({...prev, main: e.target.value}))}
                      placeholder="Contoh: PROMO RAMADHAN"
                      className="w-full bg-zinc-800 text-white text-sm p-2 rounded-lg border border-zinc-700 focus:border-teal-500 outline-none placeholder-zinc-600"
                    />
                 </div>

                 <div className="flex flex-col gap-2">
                    <label className="text-[10px] text-zinc-500">Teks Pendukung</label>
                    <textarea 
                      value={bannerTexts.support}
                      onChange={(e) => setBannerTexts(prev => ({...prev, support: e.target.value}))}
                      placeholder="Deskripsi singkat atau sub-judul..."
                      className="w-full bg-zinc-800 text-white text-sm p-2 rounded-lg border border-zinc-700 focus:border-teal-500 outline-none placeholder-zinc-600 resize-none"
                      rows={2}
                    />
                 </div>

                 <div className="flex flex-col gap-2">
                    <label className="text-[10px] text-zinc-500">Teks Footer</label>
                    <input 
                      type="text"
                      value={bannerTexts.footer}
                      onChange={(e) => setBannerTexts(prev => ({...prev, footer: e.target.value}))}
                      placeholder="Info kontak, website, atau S&K"
                      className="w-full bg-zinc-800 text-white text-sm p-2 rounded-lg border border-zinc-700 focus:border-teal-500 outline-none placeholder-zinc-600"
                    />
                 </div>

                 {/* CTA Toggle */}
                 <div className="flex items-center gap-2 pt-2 border-t border-zinc-800">
                    <input 
                      type="checkbox" 
                      id="ctaToggle"
                      checked={showCTA}
                      onChange={(e) => setShowCTA(e.target.checked)}
                      className="accent-teal-500 w-4 h-4 rounded cursor-pointer"
                    />
                    <label htmlFor="ctaToggle" className="text-xs text-white cursor-pointer select-none">Tambahkan Tombol CTA</label>
                 </div>

                 {showCTA && (
                   <div className="flex flex-col gap-2 animate-fade-in-up">
                      <input 
                        type="text"
                        value={ctaText}
                        onChange={(e) => setCtaText(e.target.value)}
                        placeholder="Teks Tombol (misal: Beli Sekarang)"
                        className="w-full bg-zinc-800 text-white text-sm p-2 rounded-lg border border-zinc-700 focus:border-teal-500 outline-none placeholder-zinc-600"
                      />
                   </div>
                 )}
            </div>
        )}

        {/* 1. EXPAND CONTROLS */}
        {isExpandMode && (
            <div className="flex flex-col gap-4 bg-zinc-900 border border-zinc-800 p-4 rounded-xl">
                 <h3 className="text-xs font-bold text-zinc-400 uppercase">1. Pilih Preset (Perluas Otomatis)</h3>
                 <div className="grid grid-cols-2 gap-2">
                   <button onClick={() => setExpandSettings({ top: 10, right: 10, bottom: 10, left: 10 })} className="p-2 bg-zinc-800 hover:bg-zinc-700 rounded text-[10px] border border-zinc-700">+10% Semua Sisi</button>
                   <button onClick={() => setExpandRatio(1, 1)} className="p-2 bg-zinc-800 hover:bg-zinc-700 rounded text-[10px] border border-zinc-700">Kotak (1:1)</button>
                   <button onClick={() => setExpandRatio(4, 5)} className="p-2 bg-zinc-800 hover:bg-zinc-700 rounded text-[10px] border border-zinc-700">Instagram Feed (4:5)</button>
                   <button onClick={() => setExpandRatio(16, 9)} className="p-2 bg-zinc-800 hover:bg-zinc-700 rounded text-[10px] border border-zinc-700">YouTube Thumbnail (16:9)</button>
                 </div>
                 <div className="border-t border-zinc-800 my-1"></div>
                 <h3 className="text-xs font-bold text-zinc-400 uppercase">2. Atur Tepian (Geser Slider)</h3>
                 <div className="grid grid-cols-2 gap-x-4 gap-y-3">
                    <div className="flex flex-col gap-1">
                        <label className="text-[10px] text-zinc-500 flex justify-between">Atas <span>{Math.round(expandSettings.top)}%</span></label>
                        <input type="range" min="0" max="100" step="1" value={expandSettings.top} onChange={(e) => setExpandSettings(s => ({...s, top: Number(e.target.value)}))} className="accent-teal-500 h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer" />
                    </div>
                    <div className="flex flex-col gap-1">
                        <label className="text-[10px] text-zinc-500 flex justify-between">Bawah <span>{Math.round(expandSettings.bottom)}%</span></label>
                        <input type="range" min="0" max="100" step="1" value={expandSettings.bottom} onChange={(e) => setExpandSettings(s => ({...s, bottom: Number(e.target.value)}))} className="accent-teal-500 h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer" />
                    </div>
                    <div className="flex flex-col gap-1">
                        <label className="text-[10px] text-zinc-500 flex justify-between">Kiri <span>{Math.round(expandSettings.left)}%</span></label>
                        <input type="range" min="0" max="100" step="1" value={expandSettings.left} onChange={(e) => setExpandSettings(s => ({...s, left: Number(e.target.value)}))} className="accent-teal-500 h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer" />
                    </div>
                    <div className="flex flex-col gap-1">
                        <label className="text-[10px] text-zinc-500 flex justify-between">Kanan <span>{Math.round(expandSettings.right)}%</span></label>
                        <input type="range" min="0" max="100" step="1" value={expandSettings.right} onChange={(e) => setExpandSettings(s => ({...s, right: Number(e.target.value)}))} className="accent-teal-500 h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer" />
                    </div>
                 </div>
                 <button onClick={handleExpandGenerate} disabled={loading || !originalImage} className={`w-full py-3 rounded-xl font-bold text-sm transition-all flex items-center justify-center gap-2 shadow-lg mt-4 ${loading || !originalImage ? 'bg-zinc-800 text-zinc-600 cursor-not-allowed border border-zinc-700' : 'bg-white text-black hover:bg-teal-50 hover:text-teal-900 shadow-teal-500/20'}`}>
                    {loading ? "Memperluas..." : "Perluas Ajaib"}
                 </button>
            </div>
        )}

        {/* 2. EDIT (INPAINT) CONTROLS */}
        {isEditMode && (
           <div className="flex flex-col gap-4 bg-zinc-900 border border-zinc-800 p-4 rounded-xl">
               <h3 className="text-xs font-bold text-zinc-400 uppercase">Pengaturan Kuas</h3>
               <div className="flex flex-col gap-2">
                  <div className="flex justify-between items-center">
                    <label className="text-xs text-zinc-500">Ukuran Kuas</label>
                    <span className="text-xs text-white font-mono">{brushSize}px</span>
                  </div>
                  <input 
                    type="range" min="5" max="100" step="1" 
                    value={brushSize} 
                    onChange={(e) => setBrushSize(Number(e.target.value))} 
                    className="w-full accent-teal-500 h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer"
                  />
               </div>
               <button onClick={clearCanvas} className="text-xs text-red-400 hover:text-red-300 border border-red-900/50 bg-red-900/10 px-3 py-2 rounded transition-colors w-full">
                  Hapus Seleksi
               </button>

               <div className="border-t border-zinc-800 pt-2"></div>

               {/* Controls for Edit Mode use custom handler */}
               <Controls 
                  onGenerate={(prompt, aspectRatio) => handleInpaintGenerate(prompt)}
                  isLoading={loading}
                  disabled={loading || !originalImage}
                  selectedFeature={selectedFeature}
               />
           </div>
        )}

        {/* 3. STANDARD CONTROLS (Fallback) */}
        {!isExpandMode && !isEditMode && (
            <Controls 
                onGenerate={(prompt, aspectRatio) => {
                   if (isMascotMode) {
                       handleMascotGenerate(prompt, aspectRatio);
                   } else if (isMultiMode || isCarouselMode || isPrewedMode) {
                       handleCompositeGenerate(prompt, aspectRatio);
                   } else if (isBannerMode) {
                       handleBannerGenerate(prompt, aspectRatio);
                   } else {
                       parentOnGenerate(prompt, aspectRatio);
                   }
                }}
                isLoading={loading}
                // Mascot/Carousel/Prewed mode allows execution even if !originalImage
                disabled={loading || (isMultiMode && uploadedImages.length < (isProductMode && !useModel ? 1 : 2)) || (!isMultiMode && !isCarouselMode && !isPrewedMode && !originalImage && !isMascotMode)}
                selectedFeature={selectedFeature}
                // HIDE INPUTS FOR FACE SWAP
                hidePromptInput={isFaceSwap}
            />
        )}
      </div>


      {/* --- RIGHT COLUMN: RESULT DISPLAY (70%) --- */}
      <div className="w-full lg:w-[70%] bg-zinc-900/30 rounded-2xl border border-zinc-800/50 p-4 relative min-h-[500px]">

        {/* Loading Overlay State */}
        {loading && (
          <div className="absolute top-4 right-4 z-10 bg-teal-600 text-white text-xs font-bold px-3 py-1.5 rounded-full shadow-lg animate-pulse flex items-center gap-2">
             <div className="w-2 h-2 bg-white rounded-full animate-bounce"></div>
             {isMultiMode && !isFaceSwap ? `Membuat Variasi ${generationCount} dari 4` : 'Memproses Gambar...'}
          </div>
        )}

        {/* CONTENT LOGIC */}
        {(isMultiMode || isMascotMode || isCarouselMode || isPrewedMode) && !isFaceSwap ? (
          <div className="flex flex-col gap-4">
            <h3 className="text-xs font-bold text-zinc-500 uppercase tracking-wider sticky top-0 bg-zinc-950/80 backdrop-blur-md py-2 z-10 rounded-lg px-2">
              {isMascotMode ? "Hasil Maskot" : (isProductMode ? "Hasil Foto Produk (4 Variasi)" : (isCarouselMode ? "Hasil Carousel (4 Slide Berurutan)" : (isPrewedMode ? "Hasil Foto Couple (4 Angle)" : "Variasi Hasil (Grid 2x2)")))}
            </h3>

            <div className={`grid gap-4 ${isMascotMode ? 'grid-cols-1 md:grid-cols-1' : 'grid-cols-1 md:grid-cols-2'}`}>
              {displayResults.map((result, index) => (
                  <div 
                    key={index} 
                    className={`relative w-full aspect-square rounded-xl overflow-hidden border-2 transition-all 
                      ${result ? 'border-teal-500/50 bg-black' : 'border-zinc-800 bg-zinc-900/50 border-dashed'}
                    `}
                  >
                      <div className="group w-full h-full relative">
                        <img src={`data:image/png;base64,${result.result}`} className="w-full h-full object-contain" />
                        <div className="absolute top-2 left-2 bg-black/60 text-white text-[10px] px-2 py-0.5 rounded backdrop-blur-sm">
                          {isCarouselMode ? `Slide ${index + 1}` : `Hasil ${index + 1}`}
                        </div>
                        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                           <a 
                            href={`data:image/png;base64,${result.result}`} 
                            download={`studio-ai-v${index+1}.png`}
                            className="p-2 bg-white text-black rounded-full hover:scale-110 transition-transform"
                            title="Unduh"
                           >
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M12 12v8.25m0-8.25l-3 3m3-3l3 3m-6-6h6m-6 0v6" />
                              </svg>
                           </a>
                           <button 
                            onClick={() => onSelectResult(result)}
                            className="p-2 bg-teal-600 text-white rounded-full hover:scale-110 transition-transform"
                            title="Lihat Layar Penuh"
                           >
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 3.75v4.5m0-4.5h4.5m-4.5 0L9 9M20.25 20.25v-4.5m0 4.5h-4.5m4.5 0L15 15M3.75 20.25h4.5m-4.5 0v-4.5m0 4.5L9 15M20.25 3.75h-4.5m4.5 0v4.5m0 4.5L15 9" />
                              </svg>
                           </button>
                        </div>
                      </div>
                  </div>
              ))}
              {displayResults.length === 0 && !loading && (
                  <div className="w-full aspect-square flex flex-col items-center justify-center text-zinc-700 bg-zinc-900/20 rounded-xl border-2 border-dashed border-zinc-800">
                      <span className="text-sm">Hasil akan muncul di sini</span>
                  </div>
              )}
            </div>
          </div>
        ) : (
          // SINGLE MODE (Or Expand/Edit Result / FaceSwap Single Result): LARGE PREVIEW
          <div className="flex flex-col">
             {/* 
                 Logic for showing result in Edit Mode:
                 1. We use ComparisonView.
                 2. originalImage is still the base original.
                 3. resultImage is from localCompositeResults if available.
             */}
             <ComparisonView 
                originalImage={isExpandMode && localCompositeResults.length > 0 
                    ? localCompositeResults[0].original 
                    : (originalImage || (uploadedImages[1] ? `data:${uploadedImages[1].mimeType};base64,${uploadedImages[1].base64}` : ''))
                }
                resultImage={
                    ((isExpandMode || isEditMode || isFaceSwap) && localCompositeResults.length > 0)
                    ? localCompositeResults[0].result
                    : (activeResultId && displayResults.find(r => r.id === activeResultId)?.result || null)
                }
                isLoading={loading}
              />

              {!originalImage && !loading && !uploadedImages[1] && (
                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-50">
                    <div className="text-center">
                      <div className="w-20 h-20 bg-zinc-800 rounded-full mx-auto mb-4 flex items-center justify-center">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1} stroke="currentColor" className="w-10 h-10 text-zinc-600">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 15.75l5.159-5.159a2.25 2.25 0 013.182 0l5.159 5.159m-1.5-1.5l1.409-1.409a2.25 2.25 0 013.182 0l2.909 2.909m-18 3.75h16.5a1.5 1.5 0 001.5-1.5V6a1.5 1.5 0 00-1.5-1.5H3.75A1.5 1.5 0 002.25 6v12a1.5 1.5 0 001.5 1.5zm10.5-11.25h.008v.008h-.008V8.25zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0z" />
                        </svg>
                      </div>
                      <p className="text-zinc-600 font-medium">Area Pratinjau</p>
                    </div>
                 </div>
              )}
          </div>
        )}

      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { Header } from './components/Header';
import { Sidebar } from './components/Sidebar';
import { Workspace } from './components/Workspace';
import { Login } from './components/Login';
import { AdminDashboard } from './components/AdminDashboard';
import { ApiKeySettings } from './components/ApiKeySettings';
import { AppState, ErrorState, FeatureItem, ProcessedImage, User } from './types';
import { editImageWithGemini, generateCompositeImage } from './services/geminiService';
import { authService } from './services/authService';

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [showAdminPanel, setShowAdminPanel] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [missingKeyAlert, setMissingKeyAlert] = useState(false);

  // App Core State
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [originalMimeType, setOriginalMimeType] = useState<string>('image/png');

  // Gallery Logic: Store up to 4 results
  const [results, setResults] = useState<ProcessedImage[]>([]);
  const [activeResultId, setActiveResultId] = useState<string | null>(null);

  const [error, setError] = useState<ErrorState>({ hasError: false, message: '' });

  const [selectedFeature, setSelectedFeature] = useState<FeatureItem | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Check auth on mount
  useEffect(() => {
    const user = authService.getCurrentUser();
    if (user) {
      // Re-verify status on reload (in case admin changed it in background/another tab simulation)
      const freshLogin = authService.login(user.email);
      if (freshLogin.success && freshLogin.user) {
         setCurrentUser(freshLogin.user);
      } else {
         authService.logout();
         setCurrentUser(null);
      }
    }
  }, []);

  // Check for API Key Availability
  useEffect(() => {
    if (currentUser) {
      const envKey = process.env.API_KEY;
      const userKey = currentUser.customApiKey;

      // If no key in Env (Vercel) and no User Custom Key, force open settings
      if ((!envKey || envKey.includes("sk-or-v1")) && !userKey) {
        setMissingKeyAlert(true);
        setShowSettings(true);
      } else {
        setMissingKeyAlert(false);
      }
    }
  }, [currentUser]);

  const handleLoginSuccess = (user: User) => {
    setCurrentUser(user);
  };

  const handleLogout = () => {
    authService.logout();
    setCurrentUser(null);
    setShowAdminPanel(false);
    setShowSettings(false);
    // Reset app state
    handleReset();
    setSelectedFeature(null);
  };

  const handleSaveApiKey = (key: string) => {
    if (currentUser) {
      const updatedUser = authService.updateUserApiKey(currentUser.email, key);
      if (updatedUser) {
        setCurrentUser(updatedUser);
        setMissingKeyAlert(false); // Clear alert on save
      }
    }
  };

  const handleImageSelected = useCallback((base64: string, mimeType: string) => {
    const fullBase64 = `data:${mimeType};base64,${base64}`;
    setOriginalImage(fullBase64);
    setOriginalMimeType(mimeType);
    setResults([]); // Clear gallery on new upload
    setActiveResultId(null);
    setAppState(AppState.UPLOADING);
    setError({ hasError: false, message: '' });
  }, []);

  const handleGenerate = useCallback(async (prompt: string, aspectRatio?: string) => {
    // Single image generation logic (for non-composite features)
    if (!originalImage) return;

    // Double check key before processing
    if (!process.env.API_KEY && !currentUser?.customApiKey) {
       setShowSettings(true);
       setMissingKeyAlert(true);
       return;
    }

    setAppState(AppState.PROCESSING);
    setError({ hasError: false, message: '' });

    try {
      const base64Raw = originalImage.split(',')[1];

      const generatedImageBase64 = await editImageWithGemini(
        base64Raw,
        originalMimeType,
        prompt,
        selectedFeature?.systemPrompt,
        aspectRatio || '1:1',
        currentUser?.customApiKey // Pass user key
      );

      const newResult: ProcessedImage = {
        id: Date.now().toString(),
        original: originalImage,
        result: generatedImageBase64,
        prompt: prompt,
        timestamp: Date.now()
      };

      setResults(prev => {
        const newHistory = [...prev, newResult];
        if (newHistory.length > 4) newHistory.shift(); 
        return newHistory;
      });

      setActiveResultId(newResult.id);
      setAppState(AppState.COMPLETE);
    } catch (err: any) {
      console.error(err);

      // If error is related to API Key
      if (err.message && (err.message.includes("API key") || err.message.includes("403"))) {
         setShowSettings(true);
         setMissingKeyAlert(true);
         setError({ hasError: true, message: "API Key tidak valid atau kadaluarsa. Silakan perbarui di Pengaturan." });
      } else {
         setError({ 
           hasError: true, 
           message: err.message || "Gagal memproses gambar." 
         });
      }
      setAppState(AppState.ERROR);
    }
  }, [originalImage, originalMimeType, selectedFeature, currentUser]);

  const handleReset = () => {
    setOriginalImage(null);
    setResults([]);
    setActiveResultId(null);
    setAppState(AppState.IDLE);
    setError({ hasError: false, message: '' });
  };

  // Wrapper for Composite generation to inject user Key
  const handleCompositeWrapper = async (
    images: { base64: string; mimeType: string }[],
    prompt: string,
    aspectRatio: string = '1:1',
    systemInstruction?: string
  ) => {
    return generateCompositeImage(
      images, 
      prompt, 
      aspectRatio, 
      systemInstruction, 
      currentUser?.customApiKey
    );
  };

  // --- RENDER LOGIC ---

  // 1. Not Logged In -> Show Login
  if (!currentUser) {
    return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  // 2. Logged In
  return (
    <div className="h-screen bg-black text-white selection:bg-teal-500/30 flex flex-col overflow-hidden">
      <div className="fixed inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none z-0"></div>

      <Header 
        onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} 
        user={currentUser}
        onLogout={handleLogout}
        onOpenAdmin={() => setShowAdminPanel(true)}
        onOpenSettings={() => setShowSettings(true)}
      />

      {/* Settings Modal */}
      {showSettings && (
        <ApiKeySettings 
          currentApiKey={currentUser.customApiKey}
          onSave={handleSaveApiKey}
          onClose={() => {
             // If key is missing, alert user they really should set it, but allow close to look around
             setShowSettings(false);
          }}
          isMandatory={missingKeyAlert}
        />
      )}

      <div className="flex flex-1 relative z-10 overflow-hidden">

        {/* If Admin Panel is Active, show it full width */}
        {showAdminPanel ? (
          <AdminDashboard onBack={() => setShowAdminPanel(false)} />
        ) : (
          <>
            <Sidebar 
              isOpen={isSidebarOpen}
              onCloseMobile={() => setIsSidebarOpen(false)}
              selectedFeatureId={selectedFeature?.id || null}
              onSelectFeature={(feature) => {
                setSelectedFeature(feature);
              }}
            />

            <main className="flex-1 h-full overflow-y-auto custom-scrollbar p-4 md:p-8 relative">

              {error.hasError && (
                <div className="w-full max-w-4xl mx-auto mb-6 bg-red-900/20 border border-red-800 text-red-200 px-4 py-3 rounded-lg flex items-center gap-3 animate-pulse">
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 text-red-500">
