import { GoogleGenAI } from "@google/genai";

const getClient = (customApiKey?: string) => {
  // Priority: 
  // 1. Custom User Key (if provided via settings)
  // 2. Environment Key (process.env.API_KEY)

  const apiKey = customApiKey || process.env.API_KEY;

  // Check for missing key OR placeholder key (often found in example .env files)
  // Also check for 'undefined' string which can happen in some build tools
  if (!apiKey || 
      apiKey.includes('sk-or-v1') || 
      apiKey.includes('YOUR_API_KEY') || 
      apiKey === 'undefined') {
    throw new Error(
      "API Key belum diatur atau tidak valid. Silakan masukkan API Key Anda di menu Pengaturan (ikon gerigi)."
    );
  }

  return new GoogleGenAI({ apiKey });
};

/**
 * Helper function to map user-friendly aspect ratios (like '2x3', '4R') 
 * to strict API supported aspect ratios (1:1, 3:4, 4:3, 16:9, 9:16).
 * ID Photos are generally portrait, so we map them to 3:4 or similar.
 */
const getValidApiAspectRatio = (ratio: string): string | undefined => {
  const validRatios = ['1:1', '16:9', '9:16', '4:3', '3:4'];
  if (validRatios.includes(ratio)) return ratio;

  // Map Pas Foto sizes to closest supported API ratio (Portrait)
  // The Prompt will enforce the specific crop, but API needs a valid container.
  switch (ratio) {
    case '2x3':
    case '3x4':
    case '4x6':
    case '4R':
    case '5R':
    case '10R':
      return '3:4'; // Standard Portrait container
    default:
      return undefined; // Let model decide or use default
  }
};

/**
 * Edits an image based on a text prompt using Gemini 2.5 Flash Image.
 * Now supports Text-to-Image if base64Image is null.
 * Supports aspect ratio configuration.
 * Supports custom API Key.
 */
export const editImageWithGemini = async (
  base64Image: string | null,
  mimeType: string,
  prompt: string,
  systemInstruction?: string,
  aspectRatio: string = '1:1',
  userApiKey?: string
): Promise<string> => {
  // Validate client creation first
  const ai = getClient(userApiKey);
  const model = 'gemini-2.5-flash-image';

  try {
    const defaultInstruction = `
      ROLE: Professional Photo Editor & Illustrator.
      TASK: Create or Edit an image based on the user's request.
      REQUIREMENTS: Maintain high quality, realistic lighting (unless stylized), and preserve key details.
    `;

    const instruction = systemInstruction || defaultInstruction;

    // Convert custom ratios (like 2x3) to valid API config (like 3:4)
    const apiAspectRatio = getValidApiAspectRatio(aspectRatio);

    const fullPrompt = `
      [SYSTEM INSTRUCTION]
      ${instruction}

      [USER REQUEST]
      "${prompt}"

      [OUTPUT CONFIGURATION]
      - Return ONLY the processed image.
      - Ensure 8K resolution quality.
      - User Requested Dimensions/Ratio: ${aspectRatio} (STRICTLY FOLLOW THIS CROP/RATIO in the image composition).
      - Do not crop the image unless necessary for the task/aspect ratio.
      - Strictly follow the ROLE and REQUIREMENTS defined above.
    `.trim();

    console.log("Sending prompt to Gemini:", fullPrompt);

    const parts: any[] = [{ text: fullPrompt }];

    // Only add image part if image exists
    if (base64Image) {
      parts.unshift({
        inlineData: {
          mimeType: mimeType,
          data: base64Image,
        },
      });
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: parts,
      },
      config: {
        imageConfig: {
          aspectRatio: apiAspectRatio,
        }
      }
    });

    if (response.candidates && response.candidates.length > 0) {
      const parts = response.candidates[0].content.parts;
      for (const part of parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }

    throw new Error("No image data returned from Gemini.");
  } catch (error: any) {
    console.error("Gemini Image Generation Error:", error);
    // Pass strictly strictly cleaned message
    throw new Error(error.message || "Failed to process image.");
  }
};

/**
 * Generates a composite image from multiple source images.
 * Supports custom API Key.
 */
export const generateCompositeImage = async (
  images: { base64: string; mimeType: string }[],
  prompt: string,
  aspectRatio: string = '1:1',
  systemInstruction?: string,
  userApiKey?: string
): Promise<string> => {
  const ai = getClient(userApiKey);
  const model = 'gemini-2.5-flash-image';

  try {
    const imageParts = images.map(img => ({
      inlineData: {
        mimeType: img.mimeType,
        data: img.base64
      }
    }));

    // Convert custom ratios for API config
    const apiAspectRatio = getValidApiAspectRatio(aspectRatio);

    const finalSystemPrompt = systemInstruction || "Create a professional composite of these images.";
    const fullPrompt = `
      [SYSTEM INSTRUCTION]
      ${finalSystemPrompt}

      [REQUIREMENTS]
      - Combine the provided ${images.length} images into a single cohesive composition.
      - Target Aspect Ratio: ${aspectRatio}.
      - Maintain photorealism and high resolution.
      - **CRITICAL: REMOVE ALL WATERMARKS, TEXT OVERLAYS, AND ARTIFACTS FOUND IN SOURCE IMAGES.**

      [USER REQUEST]
      "${prompt}"
    `.trim();

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          ...imageParts,
          { text: fullPrompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: apiAspectRatio === 'auto' ? undefined : apiAspectRatio,
        }
      }
    });

    if (response.candidates && response.candidates.length > 0) {
      const parts = response.candidates[0].content.parts;
      for (const part of parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }

    throw new Error("No composite image returned.");
  } catch (error: any) {
    console.error("Gemini Composite Error:", error);
    throw new Error(error.message || "Failed to create composite.");
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import { Header } from './components/Header';
import { Sidebar } from './components/Sidebar';
import { Workspace } from './components/Workspace';
import { Login } from './components/Login';
import { AdminDashboard } from './components/AdminDashboard';
import { ApiKeySettings } from './components/ApiKeySettings';
import { AppState, ErrorState, FeatureItem, ProcessedImage, User } from './types';
import { editImageWithGemini, generateCompositeImage } from './services/geminiService';
import { authService } from './services/authService';

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [showAdminPanel, setShowAdminPanel] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [missingKeyAlert, setMissingKeyAlert] = useState(false);

  // App Core State
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [originalMimeType, setOriginalMimeType] = useState<string>('image/png');

  // Gallery Logic: Store up to 4 results
  const [results, setResults] = useState<ProcessedImage[]>([]);
  const [activeResultId, setActiveResultId] = useState<string | null>(null);

  const [error, setError] = useState<ErrorState>({ hasError: false, message: '' });

  const [selectedFeature, setSelectedFeature] = useState<FeatureItem | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Helper to check if a key string is actually valid (not placeholder)
  const isKeyValid = (key?: string) => {
    return key && 
           key.length > 10 && 
           !key.includes("sk-or-v1") && 
           !key.includes("YOUR_API_KEY") &&
           key !== 'undefined';
  };

  // Check auth on mount
  useEffect(() => {
    const user = authService.getCurrentUser();
    if (user) {
      // Re-verify status on reload (in case admin changed it in background/another tab simulation)
      const freshLogin = authService.login(user.email);
      if (freshLogin.success && freshLogin.user) {
         setCurrentUser(freshLogin.user);
      } else {
         authService.logout();
         setCurrentUser(null);
      }
    }
  }, []);

  // Check for API Key Availability
  useEffect(() => {
    if (currentUser) {
      const envKey = process.env.API_KEY;
      const userKey = currentUser.customApiKey;

      // Strict check: If env key is missing OR is a placeholder, and user hasn't provided a custom key
      const hasValidEnvKey = isKeyValid(envKey);
      const hasValidUserKey = isKeyValid(userKey);

      if (!hasValidEnvKey && !hasValidUserKey) {
        setMissingKeyAlert(true);
        setShowSettings(true);
      } else {
        setMissingKeyAlert(false);
      }
    }
  }, [currentUser]);

  const handleLoginSuccess = (user: User) => {
    setCurrentUser(user);
  };

  const handleLogout = () => {
    authService.logout();
    setCurrentUser(null);
    setShowAdminPanel(false);
    setShowSettings(false);
    // Reset app state
    handleReset();
    setSelectedFeature(null);
  };

  const handleSaveApiKey = (key: string) => {
    if (currentUser) {
      const updatedUser = authService.updateUserApiKey(currentUser.email, key);
      if (updatedUser) {
        setCurrentUser(updatedUser);
        setMissingKeyAlert(false); // Clear alert on save
      }
    }
  };

  const handleImageSelected = useCallback((base64: string, mimeType: string) => {
    const fullBase64 = `data:${mimeType};base64,${base64}`;
    setOriginalImage(fullBase64);
    setOriginalMimeType(mimeType);
    setResults([]); // Clear gallery on new upload
    setActiveResultId(null);
    setAppState(AppState.UPLOADING);
    setError({ hasError: false, message: '' });
  }, []);

  const handleGenerate = useCallback(async (prompt: string, aspectRatio?: string) => {
    // Single image generation logic (for non-composite features)
    // Note: Some features like Mascot/Carousel don't require originalImage strictly here, handled by Workspace

    // STRICT CHECK BEFORE CALLING API
    const envKey = process.env.API_KEY;
    const userKey = currentUser?.customApiKey;
    const hasValidKey = isKeyValid(envKey) || isKeyValid(userKey);

    if (!hasValidKey) {
       setShowSettings(true);
       setMissingKeyAlert(true);
       setError({ hasError: true, message: "API Key diperlukan. Silakan masukkan di Pengaturan." });
       return;
    }

    setAppState(AppState.PROCESSING);
    setError({ hasError: false, message: '' });

    try {
      const base64Raw = originalImage ? originalImage.split(',')[1] : null;

      const generatedImageBase64 = await editImageWithGemini(
        base64Raw,
        originalMimeType,
        prompt,
        selectedFeature?.systemPrompt,
        aspectRatio || '1:1',
        currentUser?.customApiKey // Pass user key
      );

      const newResult: ProcessedImage = {
        id: Date.now().toString(),
        original: originalImage || `data:image/png;base64,${generatedImageBase64}`, // Fallback for Text-to-Image
        result: generatedImageBase64,
        prompt: prompt,
        timestamp: Date.now()
      };

      setResults(prev => {
        const newHistory = [...prev, newResult];
        if (newHistory.length > 4) newHistory.shift(); 
        return newHistory;
      });

      setActiveResultId(newResult.id);
      setAppState(AppState.COMPLETE);
    } catch (err: any) {
      console.error(err);

      // If error is related to API Key
      if (err.message && (err.message.includes("API key") || err.message.includes("403") || err.message.includes("400"))) {
         setShowSettings(true);
         setMissingKeyAlert(true);
         setError({ hasError: true, message: "API Key tidak valid atau kadaluarsa. Silakan perbarui di Pengaturan." });
      } else {
         setError({ 
           hasError: true, 
           message: err.message || "Gagal memproses gambar." 
         });
      }
      setAppState(AppState.ERROR);
    }
  }, [originalImage, originalMimeType, selectedFeature, currentUser]);

  const handleReset = () => {
    setOriginalImage(null);
    setResults([]);
    setActiveResultId(null);
    setAppState(AppState.IDLE);
    setError({ hasError: false, message: '' });
  };

  // --- RENDER LOGIC ---

  // 1. Not Logged In -> Show Login
  if (!currentUser) {
    return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  // 2. Logged In
  return (
    <div className="h-screen bg-black text-white selection:bg-teal-500/30 flex flex-col overflow-hidden">
      <div className="fixed inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none z-0"></div>

      <Header 
        onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} 
        user={currentUser}
        onLogout={handleLogout}
        onOpenAdmin={() => setShowAdminPanel(true)}
        onOpenSettings={() => setShowSettings(true)}
      />

      {/* Settings Modal */}
      {showSettings && (
        <ApiKeySettings 
          currentApiKey={currentUser.customApiKey}
          onSave={handleSaveApiKey}
          onClose={() => {
             // If key is missing, alert user they really should set it, but allow close to look around
             setShowSettings(false);
          }}
          isMandatory={missingKeyAlert}
        />
      )}

      <div className="flex flex-1 relative z-10 overflow-hidden">

        {/* If Admin Panel is Active, show it full width */}
        {showAdminPanel ? (
          <AdminDashboard onBack={() => setShowAdminPanel(false)} />
        ) : (
          <>
            <Sidebar 
              isOpen={isSidebarOpen}
              onCloseMobile={() => setIsSidebarOpen(false)}
              selectedFeatureId={selectedFeature?.id || null}
              onSelectFeature={(feature) => {
                setSelectedFeature(feature);
              }}
            />

            <main className="flex-1 h-full overflow-y-auto custom-scrollbar p-4 md:p-8 relative">

              {error.hasError && (
                <div className="w-full max-w-4xl mx-auto mb-6 bg-red-900/20 border border-red-800 text-red-200 px-4 py-3 rounded-lg flex items-center gap-3 animate-pulse">
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 text-red-500">
                    <path fillRule="evenodd" d="M9.401 3.003c1.155-2 4.043-2 5.197 0l7.355 12.748c1.154 2-.29 4.5-2.599 4.5H4.645c-2.309 0-3.752-2.5-2.599-4.5L9.4 3.003zM12 8.25a.75.75 0 01.75.75v3.75a.75.75 0 01-1.5 0V9a.75.75 0 01.75-.75zm0 8.25a.75.75 0 100-1.5.75.75 0 000 1.5z" clipRule="evenodd" />
                  </svg>
                  <p className="text-sm font-medium">{error.message}</p>
                </div>
              )}

              <Workspace 
                selectedFeature={selectedFeature}
                originalImage={originalImage}
                results={results}
                isProcessing={appState === AppState.PROCESSING}
                activeResultId={activeResultId}
                onImageSelected={handleImageSelected}
                onGenerate={handleGenerate}
                onReset={handleReset}
                onSelectResult={(res) => setActiveResultId(res.id)}
                // NEW: Pass user API key to Workspace for internal composite/edit logic
                userApiKey={currentUser.customApiKey} 
              />
            </main>
          </>
        )}
      </div>
    </div>
  );
};

export default App;

