    setCurrentUser(null);
    setShowAdminPanel(false);
    setShowSettings(false);
    // Reset app state
    handleReset();
    setSelectedFeature(null);
  };

  const handleSaveApiKey = (key: string) => {
    if (currentUser) {
      const updatedUser = authService.updateUserApiKey(currentUser.email, key);
      if (updatedUser) {
        setCurrentUser(updatedUser);
        setMissingKeyAlert(false); // Clear alert on save
      }
    }
  };

  const handleImageSelected = useCallback((base64: string, mimeType: string) => {
    const fullBase64 = `data:${mimeType};base64,${base64}`;
    setOriginalImage(fullBase64);
    setOriginalMimeType(mimeType);
    setResults([]); // Clear gallery on new upload
    setActiveResultId(null);
    setAppState(AppState.UPLOADING);
    setError({ hasError: false, message: '' });
  }, []);

  const handleGenerate = useCallback(async (prompt: string, aspectRatio?: string) => {
    // Single image generation logic (for non-composite features)

    // STRICT CHECK BEFORE CALLING API
    const envKey = process.env.API_KEY;
    const userKey = currentUser?.customApiKey;
    const hasValidKey = isKeyValid(envKey) || isKeyValid(userKey);

    if (!hasValidKey) {
       setShowSettings(true);
       setMissingKeyAlert(true);
       setError({ hasError: true, message: "API Key diperlukan. Silakan masukkan di Pengaturan." });
       return;
    }

    setAppState(AppState.PROCESSING);
    setError({ hasError: false, message: '' });

    try {
      const base64Raw = originalImage ? originalImage.split(',')[1] : null;

      const generatedImageBase64 = await editImageWithGemini(
        base64Raw,
        originalMimeType,
        prompt,
        selectedFeature?.systemPrompt,
        aspectRatio || '1:1',
        currentUser?.customApiKey // Pass user key
      );

      const newResult: ProcessedImage = {
        id: Date.now().toString(),
        original: originalImage || `data:image/png;base64,${generatedImageBase64}`, // Fallback for Text-to-Image
        result: generatedImageBase64,
        prompt: prompt,
        timestamp: Date.now()
      };

      setResults(prev => {
        const newHistory = [...prev, newResult];
        if (newHistory.length > 4) newHistory.shift(); 
        return newHistory;
      });

      setActiveResultId(newResult.id);
      setAppState(AppState.COMPLETE);
    } catch (err: any) {
      console.error(err);

      // If error is related to API Key
      if (err.message && (err.message.includes("API key") || err.message.includes("403") || err.message.includes("401"))) {
         setShowSettings(true);
         setMissingKeyAlert(true);
         setError({ hasError: true, message: "API Key tidak valid atau kadaluarsa. Cek OpenRouter/Google Key Anda." });
      } else {
         setError({ 
           hasError: true, 
           message: err.message || "Gagal memproses gambar." 
         });
      }
      setAppState(AppState.ERROR);
    }
  }, [originalImage, originalMimeType, selectedFeature, currentUser]);

  const handleReset = () => {
    setOriginalImage(null);
    setResults([]);
    setActiveResultId(null);
    setAppState(AppState.IDLE);
    setError({ hasError: false, message: '' });
  };

  // --- RENDER LOGIC ---

  // 1. Not Logged In -> Show Login
  if (!currentUser) {
    return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  // 2. Logged In
  return (
    <div className="h-screen bg-black text-white selection:bg-teal-500/30 flex flex-col overflow-hidden">
      <div className="fixed inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none z-0"></div>

      <Header 
        onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} 
        user={currentUser}
        onLogout={handleLogout}
        onOpenAdmin={() => setShowAdminPanel(true)}
        onOpenSettings={() => setShowSettings(true)}
      />

      {/* Settings Modal */}
      {showSettings && (
        <ApiKeySettings 
          currentApiKey={currentUser.customApiKey}
          onSave={handleSaveApiKey}
          onClose={() => {
             // If key is missing, alert user they really should set it, but allow close to look around
             setShowSettings(false);
          }}
          isMandatory={missingKeyAlert}
        />
      )}

      <div className="flex flex-1 relative z-10 overflow-hidden">

        {/* If Admin Panel is Active, show it full width */}
        {showAdminPanel ? (
          <AdminDashboard onBack={() => setShowAdminPanel(false)} />
        ) : (
          <>
            <Sidebar 
              isOpen={isSidebarOpen}
              onCloseMobile={() => setIsSidebarOpen(false)}
              selectedFeatureId={selectedFeature?.id || null}
              onSelectFeature={(feature) => {
                setSelectedFeature(feature);
              }}
            />

            <main className="flex-1 h-full overflow-y-auto custom-scrollbar p-4 md:p-8 relative">

              {error.hasError && (
                <div className="w-full max-w-4xl mx-auto mb-6 bg-red-900/20 border border-red-800 text-red-200 px-4 py-3 rounded-lg flex items-center gap-3 animate-pulse">
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 text-red-500">
                    <path fillRule="evenodd" d="M9.401 3.003c1.155-2 4.043-2 5.197 0l7.355 12.748c1.154 2-.29 4.5-2.599 4.5H4.645c-2.309 0-3.752-2.5-2.599-4.5L9.4 3.003zM12 8.25a.75.75 0 01.75.75v3.75a.75.75 0 01-1.5 0V9a.75.75 0 01.75-.75zm0 8.25a.75.75 0 100-1.5.75.75 0 000 1.5z" clipRule="evenodd" />
                  </svg>
                  <p className="text-sm font-medium">{error.message}</p>
                </div>
              )}

              <Workspace 
                selectedFeature={selectedFeature}
                originalImage={originalImage}
                results={results}
                isProcessing={appState === AppState.PROCESSING}
                activeResultId={activeResultId}
                onImageSelected={handleImageSelected}
                onGenerate={handleGenerate}
                onReset={handleReset}
                onSelectResult={(res) => setActiveResultId(res.id)}
                // NEW: Pass user API key to Workspace for internal composite/edit logic
                userApiKey={currentUser.customApiKey} 
              />
            </main>
          </>
        )}
      </div>
    </div>
  );
};

