import { GoogleGenAI } from "@google/genai";

const getApiKey = (customApiKey?: string) => {
  const apiKey = customApiKey || process.env.API_KEY;
  if (!apiKey || apiKey.includes('YOUR_API_KEY') || apiKey === 'undefined') {
    throw new Error(
      "API Key belum diatur. Masukkan Key Google atau OpenRouter di Pengaturan."
    );
  }
  return apiKey;
};

// Helper: Check if using OpenRouter
const isOpenRouterKey = (key: string) => key.startsWith('sk-or-');

/**
 * Handle OpenRouter API Call (Standard OpenAI Format)
 * Since OpenRouter LLMs (Gemini, Claude, GPT) return Text, not Image Binaries,
 * we handle two cases:
 * 1. Image Generation (Flux): Returns a URL in content.
 * 2. Image Editing (Gemini): Returns text description (Limitation of using Router).
 */
const callOpenRouter = async (
  apiKey: string,
  messages: any[],
  isGeneration: boolean
): Promise<string> => {

  // Use Flux Schnell for pure generation (Text-to-Image) as it's free/cheap on OpenRouter
  // Use Gemini 2.0 Flash for Image Analysis/Editing (Vision)
  const model = isGeneration ? "black-forest-labs/flux-1-schnell" : "google/gemini-2.0-flash-001";

  try {
    const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${apiKey}`,
        "HTTP-Referer": "https://studio-ai-pro.vercel.app", // Optional
        "X-Title": "Studio AI Pro", // Optional
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        model: model,
        messages: messages,
      })
    });

    if (!response.ok) {
        const err = await response.json();
        throw new Error(err.error?.message || "OpenRouter Error");
    }

    const data = await response.json();
    const content = data.choices?.[0]?.message?.content || "";

    // If using Flux or similar, the image URL usually appears in markdown `![img](url)` or plain URL
    // We try to extract it.
    const urlMatch = content.match(/\((https?:\/\/.*?)\)/) || content.match(/(https?:\/\/.*?\.(?:png|jpg|jpeg|webp))/i);

    if (urlMatch) {
       // Download the image and convert to base64
       const imageUrl = urlMatch[1] || urlMatch[0];
       const imgRes = await fetch(imageUrl);
       const blob = await imgRes.blob();
       return await new Promise((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
          reader.readAsDataURL(blob);
       });
    }

    // If it's pure text (Gemini description of edit), we can't display it as an image directly.
    // However, to keep the app from crashing, we might return a placeholder or throw.
    // For now, if no image URL found, throw informative error.
    if (!isGeneration && content) {
        throw new Error("OpenRouter: Model mengembalikan teks, bukan gambar. Coba gunakan fitur 'Generate' (Text-to-Image) dengan OpenRouter.");
    }

    throw new Error("Tidak ada gambar yang dihasilkan oleh OpenRouter.");

  } catch (error: any) {
    console.error("OpenRouter Error:", error);
    throw new Error(error.message || "Gagal menghubungi OpenRouter.");
  }
};

/**
 * Helper function to map aspect ratios
 */
const getValidApiAspectRatio = (ratio: string): string | undefined => {
  const validRatios = ['1:1', '16:9', '9:16', '4:3', '3:4'];
  if (validRatios.includes(ratio)) return ratio;
  switch (ratio) {
    case '2x3': case '3x4': case '4x6': case '4R': case '5R': case '10R': return '3:4';
    default: return undefined;
  }
};

/**
 * Main Edit Function (Router)
 */
export const editImageWithGemini = async (
  base64Image: string | null,
  mimeType: string,
  prompt: string,
  systemInstruction?: string,
  aspectRatio: string = '1:1',
  userApiKey?: string
): Promise<string> => {
  const apiKey = getApiKey(userApiKey);

  // --- ROUTE 1: OPENROUTER ---
  if (isOpenRouterKey(apiKey)) {
    const isGeneration = !base64Image; // Text-to-Image

    const messages = [];

    // System instruction
    if (systemInstruction) {
        messages.push({ role: "system", content: systemInstruction });
    }

    // User content
    const userContent: any[] = [{ type: "text", text: prompt + (aspectRatio ? ` Aspect Ratio: ${aspectRatio}` : "") }];

    if (base64Image) {
        userContent.push({
            type: "image_url",
            image_url: { url: `data:${mimeType};base64,${base64Image}` }
        });
    }

    messages.push({ role: "user", content: userContent });

    return callOpenRouter(apiKey, messages, isGeneration);
  }

  // --- ROUTE 2: GOOGLE GENAI SDK (Default) ---
  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-2.5-flash-image';
  const apiAspectRatio = getValidApiAspectRatio(aspectRatio);

  try {
    const fullPrompt = `
      [SYSTEM INSTRUCTION]
      ${systemInstruction || "Professional Photo Editor."}
      [USER REQUEST]
      "${prompt}"
      [OUTPUT CONFIGURATION]
      - Return ONLY the processed image.
      - User Requested Dimensions/Ratio: ${aspectRatio}.
      - STRICTLY FOLLOW THIS RATIO.
    `.trim();

    const parts: any[] = [{ text: fullPrompt }];
    if (base64Image) {
      parts.unshift({
        inlineData: {
          mimeType: mimeType,
          data: base64Image,
        },
      });
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: parts },
      config: { imageConfig: { aspectRatio: apiAspectRatio } }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }
    throw new Error("No image data returned from Gemini.");
  } catch (error: any) {
    throw new Error(error.message || "Failed to process image with Google SDK.");
  }
};

/**
 * Main Composite Function (Router)
 */
export const generateCompositeImage = async (
  images: { base64: string; mimeType: string }[],
  prompt: string,
  aspectRatio: string = '1:1',
  systemInstruction?: string,
  userApiKey?: string
): Promise<string> => {
  const apiKey = getApiKey(userApiKey);

  // --- ROUTE 1: OPENROUTER ---
  if (isOpenRouterKey(apiKey)) {
     // Composite via OpenRouter (likely Gemini 2.0 Flash)
     // Limitation: It will likely return text describing the composite unless we assume generation logic.
     // We will try standard chat completion.
     const messages = [];
     if (systemInstruction) messages.push({ role: "system", content: systemInstruction });

     const userContent: any[] = [{ type: "text", text: prompt }];
     images.forEach(img => {
        userContent.push({
            type: "image_url",
            image_url: { url: `data:${img.mimeType};base64,${img.base64}` }
        });
     });
     messages.push({ role: "user", content: userContent });

     return callOpenRouter(apiKey, messages, false); // false = assumes editing/analysis
  }

  // --- ROUTE 2: GOOGLE GENAI SDK ---
  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-2.5-flash-image';
  const apiAspectRatio = getValidApiAspectRatio(aspectRatio);

  try {
    const imageParts = images.map(img => ({
      inlineData: { mimeType: img.mimeType, data: img.base64 }
    }));

    const fullPrompt = `
      [SYSTEM INSTRUCTION] ${systemInstruction || "Create composite."}
      [USER REQUEST] "${prompt}"
      [REQUIREMENTS] Combine images. Ratio: ${aspectRatio}.
    `.trim();

    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: [...imageParts, { text: fullPrompt }] },
      config: { imageConfig: { aspectRatio: apiAspectRatio === 'auto' ? undefined : apiAspectRatio } }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }
    throw new Error("No composite image returned.");
  } catch (error: any) {
    throw new Error(error.message || "Failed to create composite.");
  }
};

