// Helper: Check if using OpenRouter
const isOpenRouterKey = (key: string) => key.startsWith('sk-or-');

/**
 * Handle OpenRouter API Call (Standard OpenAI Format)
 * Since OpenRouter LLMs (Gemini, Claude, GPT) return Text, not Image Binaries,
 * we handle two cases:
 * 1. Image Generation (Flux): Returns a URL in content.
 * 2. Image Editing (Gemini): Returns text description (Limitation of using Router).
 */
const callOpenRouter = async (
  apiKey: string,
  messages: any[],
  isGeneration: boolean
): Promise<string> => {

  // CRITICAL FIX: For this app, we ALWAYS need an Image Output.
  // Gemini models on OpenRouter are text-output only (multimodal input, text output).
  // To get an image, we MUST use an image generation model like Flux.
  const model = "black-forest-labs/flux-1-schnell";

  try {
    const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${apiKey}`,
        "HTTP-Referer": "https://studio-ai-pro.vercel.app", // Optional
        "X-Title": "Studio AI Pro", // Optional
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        model: model,
        messages: messages,
      })
    });

    if (!response.ok) {
        const err = await response.json();
        throw new Error(err.error?.message || "OpenRouter Error");
    }

    const data = await response.json();
    const content = data.choices?.[0]?.message?.content || "";

    // Log for debugging
    console.log("OpenRouter Response Content:", content);

    // 1. Try to find Markdown Image: ![alt](url)
    const markdownMatch = content.match(/!\[.*?\]\((https?:\/\/.*?)\)/);
    if (markdownMatch && markdownMatch[1]) {
        return await downloadAndConvert(markdownMatch[1]);
    }

    // 2. Try to find Markdown Link: [text](url)
    const linkMatch = content.match(/\[.*?\]\((https?:\/\/.*?)\)/);
    if (linkMatch && linkMatch[1]) {
        return await downloadAndConvert(linkMatch[1]);
    }

    // 3. Try to find raw URL (http...png/jpg/webp)
    const urlMatch = content.match(/(https?:\/\/[^\s)]+\.(?:png|jpg|jpeg|webp))/i);
    if (urlMatch && urlMatch[1]) {
        return await downloadAndConvert(urlMatch[1]);
    }

    // 4. Fallback: Sometimes the content IS just the URL
    if (content.startsWith("http") && content.length < 500) {
         return await downloadAndConvert(content.trim());
    }

    throw new Error("OpenRouter berhasil merespon, tetapi tidak ditemukan URL gambar dalam output. Pastikan model yang digunakan mendukung generasi gambar.");

  } catch (error: any) {
    console.error("OpenRouter Error:", error);
    throw new Error(error.message || "Gagal menghubungi OpenRouter.");
  }
};

const downloadAndConvert = async (url: string): Promise<string> => {
    try {
        const imgRes = await fetch(url);
        const blob = await imgRes.blob();
        return await new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                const res = reader.result as string;
                // Remove data:image/...;base64, prefix
                resolve(res.split(',')[1]);
            };
            reader.onerror = reject;
            reader.readAsDataURL(blob);
        });
    } catch (e) {
        throw new Error("Gagal mengunduh gambar dari OpenRouter.");
    }
}

