                        </div>
                    ))}
                 </div>
                 <button onClick={handleExpandGenerate} disabled={loading || !originalImage} className="w-full py-3 bg-white text-black font-bold text-sm rounded-xl mt-2">{loading ? "Memperluas..." : "Perluas Ajaib"}</button>
            </div>
