import { AppSettings } from "../types";

const SETTINGS_KEY = 'studio_ai_settings';

const DEFAULT_SETTINGS: AppSettings = {
  appName: 'Studio Ai Pro',
  appTagline: 'SULAP FOTO PROFESIONAL',
  themeColor: '#14b8a6', // Default Teal
  defaultApiKey: '',
  enableSecurity: false
};

export const settingsService = {
  getSettings: (): AppSettings => {
    const stored = localStorage.getItem(SETTINGS_KEY);
    if (stored) {
      return { ...DEFAULT_SETTINGS, ...JSON.parse(stored) };
    }
    return DEFAULT_SETTINGS;
  },

  saveSettings: (settings: AppSettings) => {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
    // Trigger a custom event so components can react immediately if needed
    window.dispatchEvent(new Event('settings-updated'));
  },

  // Helper to get effective API Key (User > Admin Default > Env)
  getEffectiveApiKey: (userKey?: string): string => {
    // 1. User's Custom Key
    if (userKey && userKey.length > 10) return userKey;

    // 2. Admin System Key
    const settings = settingsService.getSettings();
    if (settings.defaultApiKey && settings.defaultApiKey.length > 10) return settings.defaultApiKey;

    // 3. Environment Key (Vercel/Build time)
    return process.env.API_KEY || '';
  }
};

import { GoogleGenAI } from "@google/genai";
import { settingsService } from "./settingsService";

const getApiKey = (customApiKey?: string) => {
  // Use centralized logic to resolve key (User -> Admin Default -> Env)
  const apiKey = settingsService.getEffectiveApiKey(customApiKey);

  if (!apiKey || apiKey.includes('YOUR_API_KEY') || apiKey === 'undefined') {
    throw new Error(
      "API Key belum diatur. Administrator belum mengatur Default Key dan User belum memasukkan Key pribadi."
    );
  }
  return apiKey;
};

// Helper: Check if using OpenRouter
const isOpenRouterKey = (key: string) => key.startsWith('sk-or-');

/**
 * Handle OpenRouter API Call (Standard OpenAI Format)
 */
const callOpenRouter = async (
  apiKey: string,
  messages: any[],
  isGeneration: boolean
): Promise<string> => {

  const model = "black-forest-labs/flux-1-schnell";

  try {
    const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${apiKey}`,
        "HTTP-Referer": "https://studio-ai-pro.vercel.app", // Optional
        "X-Title": "Studio AI Pro", // Optional
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        model: model,
        messages: messages,
      })
    });

    if (!response.ok) {
        const err = await response.json();
        throw new Error(err.error?.message || "OpenRouter Error");
    }

    const data = await response.json();
    const content = data.choices?.[0]?.message?.content || "";

    console.log("OpenRouter Response Content:", content);

    // 1. Try to find Markdown Image: ![alt](url)
    const markdownMatch = content.match(/!\[.*?\]\((https?:\/\/.*?)\)/);
    if (markdownMatch && markdownMatch[1]) {
        return await downloadAndConvert(markdownMatch[1]);
    }

    // 2. Try to find Markdown Link: [text](url)
    const linkMatch = content.match(/\[.*?\]\((https?:\/\/.*?)\)/);
    if (linkMatch && linkMatch[1]) {
        return await downloadAndConvert(linkMatch[1]);
    }

    // 3. Try to find raw URL (http...png/jpg/webp)
    const urlMatch = content.match(/(https?:\/\/[^\s)]+\.(?:png|jpg|jpeg|webp))/i);
    if (urlMatch && urlMatch[1]) {
        return await downloadAndConvert(urlMatch[1]);
    }

    // 4. Fallback: Sometimes the content IS just the URL
    if (content.startsWith("http") && content.length < 500) {
         return await downloadAndConvert(content.trim());
    }

    throw new Error("OpenRouter berhasil merespon, tetapi tidak ditemukan URL gambar dalam output. Pastikan model yang digunakan mendukung generasi gambar.");

  } catch (error: any) {
    console.error("OpenRouter Error:", error);
    throw new Error(error.message || "Gagal menghubungi OpenRouter.");
  }
};

const downloadAndConvert = async (url: string): Promise<string> => {
    try {
        const imgRes = await fetch(url);
        const blob = await imgRes.blob();
        return await new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                const res = reader.result as string;
                // Remove data:image/...;base64, prefix
                resolve(res.split(',')[1]);
            };
            reader.onerror = reject;
            reader.readAsDataURL(blob);
        });
    } catch (e) {
        throw new Error("Gagal mengunduh gambar dari OpenRouter.");
    }
}

/**
 * Helper function to map aspect ratios
 */
const getValidApiAspectRatio = (ratio: string): string | undefined => {
  const validRatios = ['1:1', '16:9', '9:16', '4:3', '3:4'];
  if (validRatios.includes(ratio)) return ratio;
  switch (ratio) {
    case '2x3': case '3x4': case '4x6': case '4R': case '5R': case '10R': return '3:4';
    default: return undefined;
  }
};

/**
 * Main Edit Function (Router)
 */
export const editImageWithGemini = async (
  base64Image: string | null,
  mimeType: string,
  prompt: string,
  systemInstruction?: string,
  aspectRatio: string = '1:1',
  userApiKey?: string
): Promise<string> => {
  const apiKey = getApiKey(userApiKey);

  // --- ROUTE 1: OPENROUTER ---
  if (isOpenRouterKey(apiKey)) {
    const isGeneration = !base64Image; // Text-to-Image

    const messages = [];

    // System instruction often ignored by Flux, but we add it to user prompt for context
    const enhancedPrompt = systemInstruction 
        ? `${systemInstruction}\n\nTask: ${prompt} \n\nAspectRatio: ${aspectRatio}` 
        : `${prompt} \n\nAspectRatio: ${aspectRatio}`;

    // User content
    const userContent: any[] = [{ type: "text", text: enhancedPrompt }];

    if (base64Image) {
        userContent.push({
            type: "image_url",
            image_url: { url: `data:${mimeType};base64,${base64Image}` }
        });
    }

    messages.push({ role: "user", content: userContent });

    return callOpenRouter(apiKey, messages, isGeneration);
  }

  // --- ROUTE 2: GOOGLE GENAI SDK (Default) ---
  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-2.5-flash-image';
  const apiAspectRatio = getValidApiAspectRatio(aspectRatio);

  try {
    const fullPrompt = `
      [SYSTEM INSTRUCTION]
      ${systemInstruction || "Professional Photo Editor."}
      [USER REQUEST]
      "${prompt}"
      [OUTPUT CONFIGURATION]
      - Return ONLY the processed image.
      - User Requested Dimensions/Ratio: ${aspectRatio}.
      - STRICTLY FOLLOW THIS RATIO.
    `.trim();

    const parts: any[] = [{ text: fullPrompt }];
    if (base64Image) {
      parts.unshift({
        inlineData: {
          mimeType: mimeType,
          data: base64Image,
        },
      });
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: parts },
      config: { imageConfig: { aspectRatio: apiAspectRatio } }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }
    throw new Error("No image data returned from Gemini.");
  } catch (error: any) {
    throw new Error(error.message || "Failed to process image with Google SDK.");
  }
};

/**
 * Main Composite Function (Router)
 */
export const generateCompositeImage = async (
  images: { base64: string; mimeType: string }[],
  prompt: string,
  aspectRatio: string = '1:1',
  systemInstruction?: string,
  userApiKey?: string
): Promise<string> => {
  const apiKey = getApiKey(userApiKey);

  // --- ROUTE 1: OPENROUTER ---
  if (isOpenRouterKey(apiKey)) {
     const messages = [];

     const enhancedPrompt = systemInstruction 
        ? `${systemInstruction}\n\nTask: ${prompt} \n\nAspectRatio: ${aspectRatio}` 
        : `${prompt} \n\nAspectRatio: ${aspectRatio}`;

     const userContent: any[] = [{ type: "text", text: enhancedPrompt }];
     images.forEach(img => {
        userContent.push({
            type: "image_url",
            image_url: { url: `data:${img.mimeType};base64,${img.base64}` }
        });
     });
     messages.push({ role: "user", content: userContent });

     return callOpenRouter(apiKey, messages, false); 
  }

  // --- ROUTE 2: GOOGLE GENAI SDK ---
  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-2.5-flash-image';
  const apiAspectRatio = getValidApiAspectRatio(aspectRatio);

  try {
    const imageParts = images.map(img => ({
      inlineData: { mimeType: img.mimeType, data: img.base64 }
    }));

    const fullPrompt = `
      [SYSTEM INSTRUCTION] ${systemInstruction || "Create composite."}
      [USER REQUEST] "${prompt}"
      [REQUIREMENTS] Combine images. Ratio: ${aspectRatio}.
    `.trim();

    const response = await ai.models.generateContent({
      model: model,
      contents: { parts: [...imageParts, { text: fullPrompt }] },
      config: { imageConfig: { aspectRatio: apiAspectRatio === 'auto' ? undefined : apiAspectRatio } }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }
    throw new Error("No composite image returned.");
  } catch (error: any) {
    throw new Error(error.message || "Failed to create composite.");
  }
};

