import { User, UserStatus, UserRole } from "../types";

const STORAGE_KEY = 'studio_ai_users';
const CURRENT_USER_KEY = 'studio_ai_current_user';
const SEED_ADMIN_EMAIL = 'risangalit@gmail.com';

// Initialize with Seed Admin if not exists
const initializeUsers = (): User[] => {
  const stored = localStorage.getItem(STORAGE_KEY);
  let users: User[] = stored ? JSON.parse(stored) : [];

  const adminExists = users.find(u => u.email === SEED_ADMIN_EMAIL);
  if (!adminExists) {
    const adminUser: User = {
      email: SEED_ADMIN_EMAIL,
      role: 'ADMIN',
      status: 'ACTIVE',
      joinedAt: Date.now()
    };
    users.push(adminUser);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(users));
  }
  return users;
};

export const authService = {
  // Get currently logged in user from session
  getCurrentUser: (): User | null => {
    const stored = localStorage.getItem(CURRENT_USER_KEY);
    return stored ? JSON.parse(stored) : null;
  },

  // Login or Register (Implicit)
  login: (email: string): { success: boolean; message: string; user?: User } => {
    const users = initializeUsers();
    const normalizedEmail = email.toLowerCase().trim();

    let user = users.find(u => u.email === normalizedEmail);

    if (!user) {
      // Register new user as PENDING
      user = {
        email: normalizedEmail,
        role: 'USER',
        status: 'PENDING',
        joinedAt: Date.now()
      };
      users.push(user);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(users));
      return { success: false, message: "Akun baru berhasil dibuat. Menunggu aktivasi Administrator." };
    }

    if (user.status === 'PENDING') {
      return { success: false, message: "Akun Anda masih menunggu persetujuan Administrator." };
    }

    if (user.status === 'INACTIVE') {
      return { success: false, message: "Akun Anda telah dinonaktifkan." };
    }

    // Success login
    localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(user));
    return { success: true, message: "Login berhasil.", user };
  },

  logout: () => {
    localStorage.removeItem(CURRENT_USER_KEY);
  },

  // Update User API Key
  updateUserApiKey: (email: string, apiKey: string): User | null => {
    const users = initializeUsers();
    const index = users.findIndex(u => u.email === email);

    if (index !== -1) {
      users[index].customApiKey = apiKey;
      localStorage.setItem(STORAGE_KEY, JSON.stringify(users));

      // Update current session if it matches
      const currentUser = authService.getCurrentUser();
      if (currentUser && currentUser.email === email) {
        currentUser.customApiKey = apiKey;
        localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(currentUser));
        return currentUser;
      }
    }
    return null;
  },

  // Admin: Get all users
  getAllUsers: (): User[] => {
    return initializeUsers();
  },

  // Admin: Create new user manually
  createUser: (email: string, role: UserRole, status: UserStatus = 'ACTIVE'): User => {
    const users = initializeUsers();
    const normalizedEmail = email.toLowerCase().trim();

    if (users.find(u => u.email === normalizedEmail)) {
      throw new Error("Email pengguna sudah terdaftar.");
    }

    const newUser: User = {
      email: normalizedEmail,
      role: role,
      status: status,
      joinedAt: Date.now()
    };

    users.push(newUser);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(users));
    return newUser;
  },

  // Admin: Update user status
  updateUserStatus: (email: string, status: UserStatus): User[] => {
    const users = initializeUsers();
    const index = users.findIndex(u => u.email === email);

    if (index !== -1) {
      // Prevent deactivating the main admin
      if (users[index].email === SEED_ADMIN_EMAIL && status !== 'ACTIVE') {
        throw new Error("Tidak dapat menonaktifkan Super Admin.");
      }

      users[index].status = status;
      localStorage.setItem(STORAGE_KEY, JSON.stringify(users));
    }
    return users;
  }
};

